{
  "id": "c-mo3d6lyd-95d825b0a83b",
  "goal": "Design evidence-based decisional machinery for the planner — let the system speak for the patron via research, experts panel, steelman/arbiter, Patron Anima, and boldness mechanisms",
  "status": "live",
  "createdAt": "2026-04-17T20:32:08.101Z",
  "links": {
    "outbound": [],
    "inbound": []
