    },
    "items": [
      {
        "id": "c-mo3d6yvo-3a5947b7665e",
        "goal": "Design cost-weighted planning — track per-step disambiguation cost, let the planner trade planning cost against ambiguity reduction and skip steps",
        "status": "live"
      },
      {
        "id": "c-mo3d6xwb-5f3244f2da8e",
        "goal": "Design an ambiguity score for briefs/specs/decision-sets — measurable signal for when to stop disambiguating",
        "status": "live"
      },
      {
        "id": "c-mo3d6wol-e259ccfa381c",
        "goal": "Design arbitrary-choice mechanism for decisions confirmed purely subjective — random/election, with patron-filter for risky or irreversible subjective choices",
        "status": "live"
      },
      {
        "id": "c-mo3d6v8o-cf4d236301ed",
        "goal": "Design a Bold Agent and boldness budget — chartered solution-space exploration, N bold calls per cycle, reversibility-weighted favoring, tagging bold decisions for retrospective",
        "status": "live"
      },
      {
        "id": "c-mo3d6trd-ffe48390886f",
        "goal": "Design a Patron Anima — socratically-trained standin that carries patron taste and values for decisions without clean objective answers",
        "status": "live"
      },
      {
        "id": "c-mo3d6sl0-7099ca9c7db5",
        "goal": "Design steelman advocates and an arbiter — per-option advocates make strongest case; arbiter reviews and decides",
        "status": "live"
      },
      {
        "id": "c-mo3d6rf3-656de82910c5",
        "goal": "Design an experts panel — diverse-perspective animas (Architect, Skeptic, User Advocate, Pragmatist, Security, etc.) that identify questions and contribute to decisions",
        "status": "live"
      },
      {
        "id": "c-mo3d6q6m-26bee8de5ecb",
        "goal": "Design an external-research agent that queries open-source ADRs, case studies, architecture docs from adjacent projects",
        "status": "live"
      },
      {
        "id": "c-mo3d6pkh-45379036a238",
        "goal": "Design a canon-research agent that queries project docs, vision, prior commissions, and codebase to ground decisions in evidence",
        "status": "live"
      }
    ]
  }
}

